    // ==========================================
    menuToggle.addEventListener('click', () => {
        sidebar.classList.toggle('open');
        sidebarOverlay.classList.toggle('show');
    });

    sidebarOverlay.addEventListener('click', closeSidebar);

    function closeSidebar() {
        sidebar.classList.remove('open');
        sidebarOverlay.classList.remove('show');
    }

    // ==========================================
    // Notification Panel
    // ==========================================
    let notifPanelOpen = false;
    let notificationsData = [
        { id: 1, title: 'Lệnh sản xuất MO-2026-0041 đã được duyệt', time: '5 phút trước', icon: 'assignment', color: 'blue', read: false, target: { page: 'san-xuat', module: null } },
        { id: 2, title: 'Tồn kho NVL-035 dưới mức tối thiểu', time: '15 phút trước', icon: 'warning', color: 'orange', read: false, target: { page: 'kho-van', module: DSHH_TITLE, itemId: 'SP-001' } },
        { id: 3, title: 'QC công đoạn May - Lô #127 đạt 100%', time: '30 phút trước', icon: 'check_circle', color: 'green', read: false, target: { page: 'san-xuat', module: null } },
        { id: 4, title: 'Nhân viên mới: Nguyễn Văn A - Phòng Sản xuất', time: '1 giờ trước', icon: 'person', color: 'purple', read: false, target: { page: 'nhan-su', module: 'Nhân viên' } }
    ];

    function updateNotificationBadge() {
        if (!notificationBtn) return;
        const unreadCount = notificationsData.filter(n => !n.read).length;
        const badge = notificationBtn.querySelector('.notification-badge');
        if (badge) {
            if (unreadCount > 0) {
                badge.style.display = 'flex';
                badge.textContent = unreadCount;
            } else {
                badge.style.display = 'none';
            }
        }
    }

    function renderNotificationsList() {
        const listEl = document.querySelector('.notification-list');
        if (!listEl) return;

        if (notificationsData.length === 0) {
            listEl.innerHTML = '<div style="padding: 20px; text-align: center; color: var(--text-muted); font-size: 13px;">Không có thông báo nào</div>';
            return;
        }

        listEl.innerHTML = notificationsData.map(n => `
            <div class="notification-item ${n.read ? 'read' : ''}" data-id="${n.id}" style="opacity: ${n.read ? '0.6' : '1'}">
                <div class="notif-icon" style="background:var(--icon-${n.color}-bg);color:var(--icon-${n.color})">
                    <span class="material-icons-outlined" style="font-size:18px">${n.icon}</span>
                </div>
                <div class="notif-body">
                    <div class="notif-title" style="font-weight: ${n.read ? '400' : '600'}">${n.title}</div>
                    <div class="notif-time">${n.time}</div>
                </div>
                ${!n.read ? '<div style="width: 8px; height: 8px; background: var(--primary); border-radius: 50%; margin-top: 5px; flex-shrink: 0;"></div>' : ''}
            </div>
        `).join('');

        // Attach events to items
        listEl.querySelectorAll('.notification-item').forEach(item => {
            item.addEventListener('click', (e) => {
                e.stopPropagation();
                const id = parseInt(item.dataset.id);
                const notif = notificationsData.find(n => n.id === id);
                if (notif) {
                    if (!notif.read) {
                        notif.read = true;
                        updateNotificationBadge();
                    }

                    // Close notification panel
                    notifPanelOpen = false;
                    const panel = document.querySelector('.notification-panel');
                    if (panel) panel.classList.remove('show');

                    // Navigate to target
                    if (notif.target) {
                        window.erpApp.navigateToModule(notif.target.page, notif.target.module, notif.target.itemId);
                    }

                    renderNotificationsList();
                }
            });
        });
    }

    window.erpApp.navigateToModule = function (page, moduleTitle, itemId = null) {
        navigateTo(page);
        if (moduleTitle) {
            window.erpApp.openModule(moduleTitle, document.getElementById('pageContent'));

            // Set search query if itemId is provided to filter/highlight
            if (itemId) {
                if (moduleTitle === DSHH_TITLE) {
                    dshhSearchQuery = itemId.toLowerCase();
                    window.erpApp.renderDanhSachHangHoa();
                } else if (moduleTitle === DSK_TITLE) {
                    dskSearchQuery = itemId.toLowerCase();
                    window.erpApp.renderDanhSachKho();
                } else if (moduleTitle === DSDT_TITLE) {
                    dsdtSearchQuery = itemId.toLowerCase();
                    window.erpApp.renderDanhSachDoiTac();
                }
            }
        }
    };

    window.erpApp.addNotification = function (title, icon, color, target) {
        const id = Date.now();
        const time = 'Vừa xong';
        notificationsData.unshift({ id, title, time, icon, color, read: false, target });
        updateNotificationBadge();
        if (notifPanelOpen) renderNotificationsList();
    };

    notificationBtn.addEventListener('click', (e) => {
        e.stopPropagation();
        notifPanelOpen = !notifPanelOpen;
        let panel = document.querySelector('.notification-panel');
        if (!panel) {
            panel = createNotificationPanel();
            document.body.appendChild(panel);
        }
        renderNotificationsList();
        panel.classList.toggle('show', notifPanelOpen);
    });

    document.addEventListener('click', () => {
        const panel = document.querySelector('.notification-panel');
        if (panel) {
            panel.classList.remove('show');
            notifPanelOpen = false;
        }
    });

    function createNotificationPanel() {
        const panel = document.createElement('div');
        panel.className = 'notification-panel';
        panel.addEventListener('click', e => e.stopPropagation());

        // Header
        const header = document.createElement('div');
        header.className = 'notification-panel-header';
        header.innerHTML = `
            <h3>Thông báo</h3>
            <span class="mark-all-read" style="cursor:pointer; color:var(--primary); font-size: 11px; font-weight: 500;">Đánh dấu đã đọc</span>
        `;

        header.querySelector('.mark-all-read').addEventListener('click', (e) => {
            e.stopPropagation();
            if (notificationsData.every(n => n.read)) return;
            notificationsData.forEach(n => n.read = true);
            renderNotificationsList();
            updateNotificationBadge();
            if (typeof showToast === 'function') {
                showToast('Đã đánh dấu tất cả là đã đọc');
            }
        });

        panel.appendChild(header);

        // List container
        const listContainer = document.createElement('div');
        listContainer.className = 'notification-list';
        panel.appendChild(listContainer);

        return panel;
    }

    // Initialize badge on load
    updateNotificationBadge();

    // ==========================================
    // Render Page
    // ==========================================
    function renderPage() {
        const page = pagesData[currentPage];
        if (!page) return;

        // Special pages
        if (currentPage === 'trang-chu') {
            renderHomePage();
            return;
        }

        if (currentPage === 'ban-quyen') {
            renderCopyrightPage();
            return;
        }

        if (currentPage === 'ho-so-ca-nhan') {
            renderProfilePage();
            return;
        }

        if (currentPage === 'dieu-hanh') {
            window.erpApp.renderDieuHanh();
            return;
        }

        if (page.sections.length === 0) {
            renderPlaceholder(page);
            return;
        }

        let html = `
            <div class="page-top-bar">
                <button class="back-btn" onclick="window.erpApp.goHome()">
                    <span class="material-icons-outlined">arrow_back</span>
                    Quay lại
                </button>
                <div class="tab-group">
                    <button class="tab-btn ${activeTab === 'all' ? 'active' : ''}" onclick="window.erpApp.setTab('all')">Tất cả</button>
                    <button class="tab-btn ${activeTab === 'starred' ? 'active' : ''}" onclick="window.erpApp.setTab('starred')">Đánh Dấu</button>
                </div>
                <div class="search-box">
                    <span class="material-icons-outlined">search</span>
                    <input type="text" id="searchInput" placeholder="Tìm module theo tên hoặc mô tả..." value="${searchQuery}" oninput="window.erpApp.onSearch(this.value)">
                </div>
            </div>
        `;

        const filteredSections = getFilteredSections(page.sections);

        if (filteredSections.length === 0) {
            html += `
                <div class="page-placeholder" style="height:40vh">
                    <div class="placeholder-icon">
                        <span class="material-icons-outlined">search_off</span>
                    </div>
                    <h2>Không tìm thấy kết quả</h2>
                    <p>Thử tìm kiếm với từ khoá khác hoặc xoá bộ lọc.</p>
                </div>
            `;
        } else {
            filteredSections.forEach(section => {
                html += `
                    <div class="module-section">
                        <div class="section-title">${section.title}</div>
                        <div class="module-grid">
                            ${section.modules.map(mod => renderCard(mod)).join('')}
                        </div>
                    </div>
                `;
            });
        }

        pageContent.innerHTML = html;
    }

    function getFilteredSections(sections) {
        const q = searchQuery.toLowerCase().trim();
        const result = [];

        sections.forEach(section => {
            let mods = section.modules;

            // Filter by starred
            if (activeTab === 'starred') {
                mods = mods.filter(m => starredModules.has(m.title));
            }

            // Filter by search
            if (q) {
                mods = mods.filter(m =>
                    m.title.toLowerCase().includes(q) ||
                    m.desc.toLowerCase().includes(q)
                );
            }

            if (mods.length > 0) {
                result.push({ ...section, modules: mods });
            }
        });

        return result;
    }

    function renderCard(mod) {
        const isStarred = starredModules.has(mod.title);
        return `
            <div class="module-card" onclick="window.erpApp.openModule('${mod.title.replace(/'/g, "\\'")}')">
                <div class="card-icon ${mod.color}">
                    <span class="material-icons-outlined">${mod.icon}</span>
                </div>
                <div class="card-body">
                    <div class="card-title">${mod.title}</div>
                    <div class="card-desc">${mod.desc}</div>
                </div>
                <div class="card-chevron">
                    <span class="material-icons-outlined">chevron_right</span>
                </div>
                <!-- Hidden star button - keep functionality accessible via hover or context if needed -->
                <button class="card-star-btn ${isStarred ? 'starred' : ''}" onclick="event.stopPropagation(); window.erpApp.toggleStar('${mod.title.replace(/'/g, "\\'")}')">
                    <span class="material-icons-outlined">${isStarred ? 'star' : 'star_border'}</span>
                </button>
            </div>
        `;
    }

    // ==========================================
    // Home Page
    // ==========================================
    let homeTab = 'functions'; // 'functions' | 'starred' | 'all'

    function renderHomePage() {
        // All modules for the home grid
        const homeModules = [
            { page: 'hanh-chinh', icon: 'description', color: 'red', title: 'Hành chính', desc: 'Công văn, hợp đồng, hồ sơ nhân sự, tiền lương.' },
            { page: 'van-hanh', icon: 'miscellaneous_services', color: 'green', title: 'Vận hành', desc: 'Quản lý vận hành, giám sát và quy trình (Process&Risk).' },
            { page: 'kinh-doanh', icon: 'storefront', color: 'blue', title: 'Kinh doanh', desc: 'Bán hàng, khách hàng, cơ hội và báo các kinh doanh.' },
            { page: 'marketing', icon: 'campaign', color: 'purple', title: 'Marketing', desc: 'Chiến dịch, khách hàng, báo cáo marketing.' },
            { page: 'tai-chinh', icon: 'account_balance', color: 'teal', title: 'Tài chính', desc: 'Kế toán, ngân sách, báo cáo tài chính.' },
            { page: 'mua-hang', icon: 'shopping_cart', color: 'orange', title: 'Mua hàng', desc: 'Đề xuất vật tư, đơn đặt hàng, đối tác.' },
            { page: 'san-xuat', icon: 'precision_manufacturing', color: 'coral', title: 'Sản xuất', desc: 'Kế hoạch sản xuất, quản lý sản xuất.' },
            { page: 'kho-van', icon: 'inventory_2', color: 'blue', title: 'Kho vận', desc: 'Tồn kho, xuất nhập kho, vận chuyển.' },
            { page: 'dieu-hanh', icon: 'dashboard', color: 'green', title: 'Điều hành', desc: 'Điều hành, giám sát và vận hành.' },
            { page: 'he-thong', icon: 'settings', color: 'navy', title: 'Hệ thống', desc: 'Cấu hình, phân quyền và nhiều sự.' },
            { page: 'tro-ly-ai', icon: 'smart_toy', color: 'green', title: 'Trợ lý AI', desc: 'Cấu hình, phân quyền và nhiều sự.' },
            { page: 'ban-quyen', icon: 'info', color: 'teal', title: 'Thông tin bản quyền', desc: 'Quản lý sở hữu trí tuệ và thông tin nhà phát triển.' }
        ];

        // Determine greeting based on time
        const hour = new Date().getHours();
        let greeting = 'Chào buổi sáng';
        if (hour >= 12 && hour < 18) greeting = 'Chào buổi chiều';
        else if (hour >= 18) greeting = 'Chào buổi tối';

        // Filter modules based on tab
        let displayModules = homeModules;
        if (homeTab === 'starred') {
            displayModules = homeModules.filter(m => starredModules.has(m.title));
        }

        let html = `
            <div class="home-page">
                <div class="home-greeting" style="animation: fadeInUp 0.4s ease both;">
                    <h1 class="greeting-text">${greeting}, ${currentUser ? currentUser.fullName : 'Người dùng'} 👋</h1>
                </div>
                <div class="home-tabs">
                    <button class="home-tab ${homeTab === 'functions' ? 'active' : ''}" onclick="window.erpApp.setHomeTab('functions')">Chức năng</button>
                    <button class="home-tab ${homeTab === 'starred' ? 'active' : ''}" onclick="window.erpApp.setHomeTab('starred')">Đánh dấu</button>
                    <button class="home-tab ${homeTab === 'all' ? 'active' : ''}" onclick="window.erpApp.setHomeTab('all')">Tất cả</button>
                </div>
        `;

        if (displayModules.length === 0) {
            html += `
                <div class="page-placeholder" style="height:40vh">
                    <div class="placeholder-icon">
                        <span class="material-icons-outlined">star_border</span>
                    </div>
                    <h2>Chưa có module nào được đánh dấu</h2>
                    <p>Đánh dấu sao ⭐ các module yêu thích để truy cập nhanh tại đây.</p>
                </div>
            `;
        } else {
            html += `<div class="home-grid">`;
            displayModules.forEach((mod, index) => {
                html += `
                    <div class="home-module-card" onclick="window.erpApp.navigateTo('${mod.page}')" style="animation-delay: ${index * 0.04}s">
                        <div class="home-card-icon ${mod.color}">
                            <span class="material-icons-outlined">${mod.icon}</span>
                        </div>
                        <div class="home-card-title">${mod.title}</div>
                        <div class="home-card-desc">${mod.desc}</div>
                    </div>
                `;
            });
            html += `</div>`;
        }

        html += `</div>`;
        pageContent.innerHTML = html;
    }

