    window.erpApp.createBackupProcess = () => {
        const overlay = document.createElement('div');
        overlay.className = 'modal-overlay';
        overlay.id = 'backupProgressModal';
        overlay.innerHTML = `
            <div class="modal-content" style="max-width:450px; text-align:center; padding:40px;">
                <div id="backupIcon" class="material-icons-outlined" style="font-size:64px; color:#3b82f6; margin-bottom:20px; transition:all 0.5s;">cloud_upload</div>
                <h3 id="backupStatusText" style="margin-bottom:12px; font-size:18px; color:#1e293b;">Đang chuẩn bị gói dữ liệu...</h3>
                <div style="width:100%; height:8px; background:#f1f5f9; border-radius:4px; margin-bottom:20px; overflow:hidden;">
                    <div id="backupProgressBar" style="width:0%; height:100%; background:linear-gradient(90deg, #3b82f6 0%, #6366f1 100%); transition:width 0.1s ease-out;"></div>
                </div>
                <p style="color:#64748b; font-size:13px;">Hệ thống đang nén và mã hóa toàn bộ cơ sở dữ liệu. Vui lòng không đóng cửa sổ này.</p>
            </div>
        `;
        document.body.appendChild(overlay);

        let progress = 0;
        const bar = document.getElementById('backupProgressBar');
        const text = document.getElementById('backupStatusText');
        const icon = document.getElementById('backupIcon');

        const interval = setInterval(() => {
            progress += Math.random() * 5;
            if (progress >= 100) {
                progress = 100;
                clearInterval(interval);
                bar.style.width = '100%';
                text.textContent = 'Sao lưu hoàn tất!';
                icon.textContent = 'check_circle';
                icon.style.color = '#10b981';

                setTimeout(() => {
                    overlay.remove();
                    window.erpApp.exportAllData();
                    // Thêm vào lịch sử (giả lập)
                    backupHistory.unshift({
                        id: 'BK' + Date.now().toString().slice(-3),
                        date: new Date().toLocaleString('vi-VN'),
                        type: 'Thủ công',
                        size: '15.5 MB',
                        status: 'success',
                        file: 'erp_backup_manual_' + new Date().toISOString().slice(0, 10).replace(/-/g, '') + '.json'
                    });
                    renderSaoLuu('history');
                }, 1000);
            } else {
                bar.style.width = progress + '%';
                if (progress > 30) text.textContent = 'Đang trích xuất bản ghi...';
                if (progress > 60) text.textContent = 'Đang nén dữ liệu...';
                if (progress > 85) text.textContent = 'Mã hóa và tải xuống...';
            }
        }, 100);
    };

    window.erpApp.viewBackupGroupDetail = (key) => {
        const group = [
            { key: 'erp_employees', name: 'Nhân sự', icon: 'people' },
            { key: 'erp_products', name: 'Hàng hóa', icon: 'inventory_2' },
            { key: 'erp_phieu_kho', name: 'Kho vận', icon: 'local_shipping' },
            { key: 'erp_customers', name: 'Khách hàng', icon: 'handshake' },
            { key: 'erp_campaigns', name: 'Marketing', icon: 'ads_click' },
            { key: 'erp_production_orders', name: 'Sản xuất', icon: 'precision_manufacturing' }
        ].find(g => g.key === key);

        if (!group) return;

        const data = JSON.parse(localStorage.getItem(key)) || [];

        const overlay = document.createElement('div');
        overlay.className = 'modal-overlay';
        overlay.innerHTML = `
            <div class="modal-content" style="max-width:500px;">
                <div class="modal-header">
                    <h2><span class="material-icons-outlined">${group.icon}</span> Thống kê dữ liệu: ${group.name}</h2>
                    <button class="modal-close" onclick="this.closest('.modal-overlay').remove()"><span class="material-icons-outlined">close</span></button>
                </div>
                <div class="modal-body" style="padding:24px;">
                    <div style="display:flex; justify-content:space-between; margin-bottom:20px;">
                        <div style="text-align:center; padding:16px; background:#f8fafc; border-radius:12px; flex:1; margin-right:8px;">
                            <div style="font-size:24px; font-weight:800; color:#3b82f6;">${data.length}</div>
                            <div style="font-size:12px; color:#64748b; font-weight:600; text-transform:uppercase;">Số bản ghi</div>
                        </div>
                        <div style="text-align:center; padding:16px; background:#f8fafc; border-radius:12px; flex:1; margin-left:8px;">
                            <div style="font-size:24px; font-weight:800; color:#10b981;">100%</div>
                            <div style="font-size:12px; color:#64748b; font-weight:600; text-transform:uppercase;">Độ tin cậy</div>
                        </div>
                    </div>
                    <div style="background:#f1f5f9; padding:16px; border-radius:12px;">
                        <div style="font-size:13px; font-weight:700; color:#1e293b; margin-bottom:12px;">Cấu trúc JSON đính kèm:</div>
                        <pre style="font-size:11px; color:#475569; background:#fff; padding:12px; border-radius:8px; border:1px solid #e2e8f0; overflow:auto; max-height:200px;">${JSON.stringify(data.slice(0, 1), null, 2)}</pre>
                    </div>
                </div>
                <div class="modal-footer">
                    <button onclick="window.erpApp.exportSingleGroup('${key}')" class="btn-save" style="background:#6366f1;">
                        <span class="material-icons-outlined">download</span> Tải xuống
                    </button>
                    <button class="btn-cancel" onclick="this.closest('.modal-overlay').remove()">Đóng</button>
                </div>
            </div>
        `;
        document.body.appendChild(overlay);
    };

    window.erpApp.exportSingleGroup = (key) => {
        const data = JSON.parse(localStorage.getItem(key)) || [];
        const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `erp_${key}_${new Date().toISOString().slice(0, 10)}.json`;
        a.click();
        showToast('Đã tải xuống bộ dữ liệu thành công!');
    };

    // ==========================================
    // MODULE: Thiết bị đăng nhập (Sessions)
    // ==========================================
