                    { id: 'market', title: 'Tầm nhìn quy mô & Thị phần', desc: 'Thiết lập chỉ tiêu quy mô, thị phần theo năm và biểu đồ.', icon: 'history_toggle_off', color: '#10b981' },
                    { id: 'competitor', title: 'Phân tích đối thủ', desc: 'Theo dõi đối thủ, điểm mạnh/yếu, battlecard và nhật ký biến động.', icon: 'trending_up', color: '#06b6d4' },
                    { id: 'swot', title: 'Phân tích SWOT', desc: 'Điểm mạnh, điểm yếu, cơ hội, nguy cơ; cập nhật theo kỳ.', icon: 'grid_view', color: '#6366f1' }
