    window.erpApp.getFilteredCrm = function () {
        return customers.filter(c => {
            const q = crmSearchQuery.toLowerCase();
            const matchSearch = c.name.toLowerCase().includes(q) || c.phone.includes(q) || c.email.toLowerCase().includes(q) || c.id.toLowerCase().includes(q);
            const matchTab = crmActiveTab === 'all' || c.status === crmActiveTab;
            return matchSearch && matchTab;
        });
    }

    window.erpApp.getCustomerStatusLabel = function (status) {
        const m = { 'potential': 'Tiềm năng', 'active': 'Đang giao dịch', 'vip': 'VIP', 'inactive': 'Tạm ngừng' };
        return m[status] || status;
    }

    window.erpApp.getCustomerStatusColor = function (status) {
        const m = {
            'potential': { bg: '#fff7ed', text: '#f97316', border: '#ffedd5' }, // Orange
            'active': { bg: '#eff6ff', text: '#3b82f6', border: '#dbeafe' }, // Blue
            'vip': { bg: '#fdf4ff', text: '#d946ef', border: '#fae8ff' }, // Fuchsia/Purple
            'inactive': { bg: '#f8fafc', text: '#64748b', border: '#e2e8f0' } // Gray
        };
        return m[status] || m.potential;
    }

