        const c = isEdit ? customers.find(x => x.id === id) : {
            id: 'KH-' + new Date().getFullYear() + '-' + Date.now().toString().slice(-3),
            name: '', type: 'Cá nhân', phone: '', email: '', address: '', status: 'potential', notes: ''
        };

