    window.erpApp.closeGrModal = function () {
        const m = document.getElementById('grModal');
        if (m) m.remove();
    }

    window.erpApp.addGrItemRow = function () {
        const tbody = document.getElementById('grItemsBody');
        if (!tbody) return;
        const nextIdx = tbody.children.length + '_' + Date.now().toString().slice(-4);
        const tr = document.createElement('tr');
        tr.style.cssText = 'border-bottom:1px solid #f1f5f9;';
        tr.innerHTML = `
            <td style="padding:10px;"><input type="text" name="gItemName_${nextIdx}" value="" required style="width:100%; border:1px solid transparent; padding:4px 8px; border-radius:4px; outline:none; background:transparent;" onfocus="this.style.border='1px solid #6ee7b7'" onblur="this.style.border='1px solid transparent'"></td>
            <td style="padding:10px;"><input type="text" name="gItemUnit_${nextIdx}" value="Cái" required style="width:100%; border:1px solid transparent; padding:4px 8px; border-radius:4px; outline:none; background:transparent;" onfocus="this.style.border='1px solid #6ee7b7'" onblur="this.style.border='1px solid transparent'"></td>
            <td style="padding:10px;"><input type="number" name="gItemQtyOrd_${nextIdx}" value="1" required min="1" style="width:100%; border:1px solid transparent; padding:4px 8px; border-radius:4px; outline:none; background:transparent; text-align:right;" onfocus="this.style.border='1px solid #6ee7b7'" onblur="this.style.border='1px solid transparent'"></td>
            <td style="padding:10px;"><input type="number" name="gItemQtyRec_${nextIdx}" value="1" required min="0" style="width:100%; border:1px solid transparent; padding:4px 8px; border-radius:4px; outline:none; background:#ecfdf5; text-align:right; font-weight:700; color:#059669;" onfocus="this.style.border='1px solid #6ee7b7'" onblur="this.style.border='1px solid transparent'"></td>
            <td style="padding:10px; text-align:center;">
                <select name="gItemCond_${nextIdx}" style="padding:4px; border:1px solid #e2e8f0; border-radius:4px; outline:none; width:90%; font-size:12px;">
                    <option value="Tốt">Tốt</option>
                    <option value="Lỗi">Hàng lỗi</option>
                    <option value="Thiếu">Giao thiếu</option>
                    <option value="Sai hàng">Giao sai</option>
                </select>
            </td>
            <td style="padding:10px;"><input type="url" name="gItemImg_${nextIdx}" value="" placeholder="HTTP..." style="width:100%; border:1px dashed #cbd5e1; padding:4px 8px; border-radius:4px; outline:none; background:transparent; font-size:11px;" onfocus="this.style.border='1px solid #f87171'" onblur="this.style.border='1px dashed #cbd5e1'"></td>
            <td style="padding:10px; text-align:center;"><span class="material-icons-outlined" onclick="this.closest('tr').remove();" style="color:#ef4444; font-size:16px; cursor:pointer;">delete</span></td>
        `;
        tbody.appendChild(tr);
    };

    window.erpApp.saveGR = function (e) {
        e.preventDefault();
        const formData = new FormData(e.target);
        const data = Object.fromEntries(formData.entries());

        const rawKeys = Object.keys(data);
        const itemNamesKeys = rawKeys.filter(k => k.startsWith('gItemName_'));
        const items = [];
        itemNamesKeys.forEach(key => {
            const idx = key.split('_')[1];
            items.push({
                name: data['gItemName_' + idx],
                unit: data['gItemUnit_' + idx],
                qtyOrdered: parseFloat(data['gItemQtyOrd_' + idx]) || 0,
                qtyReceived: parseFloat(data['gItemQtyRec_' + idx]) || 0,
                condition: data['gItemCond_' + idx],
                defectImg: data['gItemImg_' + idx] || ''
            });
        });

        const newR = {
            id: data.id,
            poId: data.poId,
            status: data.status,
            supplier: data.supplier,
            inspector: data.inspector,
            date: data.date,
            items: items
        };

        if (index > -1) {
            goodsReceipts[index] = newR;
            if (window.CrudSync) window.CrudSync.saveItem('goods_receipts', newR, 'id');
        } else {
            goodsReceipts.unshift(newR);
            if (window.CrudSync) window.CrudSync.saveItem('goods_receipts', newR, 'id');
        }

        // localStorage.setItem('erp_goodsReceipts', JSON.stringify(goodsReceipts));
        window.erpApp.closeGrModal();
        showToast('Đã lưu dữ liệu Phiếu Kiểm Tra Hàng!');
        renderKiemTraNhapHang();
    };

    window.erpApp.confirmDeleteGR = function (id) {
        if (confirm('Lập tức Hủy Biên Bản nhận hàng ' + id + '?')) {
            goodsReceipts = goodsReceipts.filter(x => x.id !== id);
            if (window.CrudSync) window.CrudSync.deleteItem('goods_receipts', id);
            // localStorage.setItem('erp_goodsReceipts', JSON.stringify(goodsReceipts));
            showToast('Đã xóa dữ liệu GR!');
            renderKiemTraNhapHang();
        }
    };

    window.erpApp.grSearch = function (val) {
        grSearchQuery = val;
        renderKiemTraNhapHang();
    };

    window.erpApp.grSetTab = function (tab) {
        grActiveTab = tab;
        renderKiemTraNhapHang();
    };


    // ==========================================
    // MODULE: Báo cáo mua hàng 
    // ==========================================
    function renderBaoCaoMuaHang() {
        breadcrumbCurrent.textContent = 'Báo cáo mua hàng';
        pageBadge.textContent = 'Mua hàng';

        // Fake Data computations
        const totalPO = purchaseOrders.length;
        const totalSpent = purchaseOrders.reduce((sum, po) => sum + (po.status !== 'cancelled' ? po.totalAmount : 0), 0);
        const pendingPO = purchaseOrders.filter(po => po.status === 'draft' || po.status === 'ordered').length;
        const formatter = new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' });

        let supplierTotals = {};
        purchaseOrders.filter(po => po.status !== 'cancelled').forEach(po => {
            if (!supplierTotals[po.supplier]) supplierTotals[po.supplier] = 0;
            supplierTotals[po.supplier] += po.totalAmount;
        });

        // Get Top 5 suppliers
        const topSuppliers = Object.entries(supplierTotals)
            .map(([name, amount]) => ({ name, amount }))
            .sort((a, b) => b.amount - a.amount).slice(0, 5);

        // Chart Data Calculation
        const chartCounts = { draft: 0, ordered: 0, received: 0, cancelled: 0 };
        purchaseOrders.forEach(po => {
            if (chartCounts[po.status] !== undefined) chartCounts[po.status]++;
        });
        const getPct = (val) => totalPO > 0 ? (val / totalPO * 100).toFixed(1) : 0;

        let html = `
            <div class="sales-order-module">
                <div class="so-toolbar" style="display:flex; align-items:center; justify-content:space-between; margin-bottom:24px; gap:16px; flex-wrap:wrap;">
                    <div style="display:flex; align-items:center; gap:12px;">
                        <button class="back-btn" onclick="window.erpApp.navigateTo('mua-hang')" style="padding:8px 16px; border:1px solid #e2e8f0; background:#fff; border-radius:8px; display:flex; align-items:center; gap:8px; font-weight:600; color:#64748b; cursor:pointer;">
                            <span class="material-icons-outlined">arrow_back</span> Quay lại
                        </button>
                        <h2 style="font-size:18px; font-weight:800; color:#1e293b; margin:0;">Tổng quan Chi phí & Mua sắm</h2>
                    </div>
                    <div>
                        <button onclick="window.erpApp.simulatePrintPurchasingReport()" style="padding:10px 24px; background:linear-gradient(135deg, #f59e0b 0%, #d97706 100%); color:#fff; border:none; border-radius:10px; font-weight:700; font-size:14px; display:flex; align-items:center; gap:8px; cursor:pointer; box-shadow:0 4px 12px rgba(245, 158, 11, 0.2);">
                            <span class="material-icons-outlined">picture_as_pdf</span> Xuất Báo Cáo PDF
                        </button>
                    </div>
                </div>

                <div style="display:grid; grid-template-columns:repeat(auto-fit, minmax(250px, 1fr)); gap:20px; margin-bottom:24px;">
                    <div style="background:#fff; border:1px solid #e2e8f0; border-radius:16px; padding:24px; box-shadow:0 4px 20px rgba(0,0,0,0.02); display:flex; flex-direction:column; gap:10px;">
                        <div style="font-size:13px; font-weight:700; color:#64748b; text-transform:uppercase; letter-spacing:1px;">Tổng chi phí Thực Nhận & Đã Đặt</div>
                        <div style="font-size:28px; font-weight:900; color:#10b981;">${formatter.format(totalSpent)}</div>
                        <div style="font-size:12px; color:#94a3b8; font-weight:600;">(Đã loại trừ Đơn hủy)</div>
                    </div>
                    <div style="background:#fff; border:1px solid #e2e8f0; border-radius:16px; padding:24px; box-shadow:0 4px 20px rgba(0,0,0,0.02); display:flex; flex-direction:column; gap:10px;">
                        <div style="font-size:13px; font-weight:700; color:#64748b; text-transform:uppercase; letter-spacing:1px;">Lượng Đơn Đặt Hàng (PO)</div>
                        <div style="display:flex; align-items:flex-end; gap:8px;">
                            <span style="font-size:28px; font-weight:900; color:#3b82f6;">${totalPO}</span>
                            <span style="font-size:13px; font-weight:700; color:#64748b; margin-bottom:6px;">phiếu xuất</span>
                        </div>
                        <div style="font-size:12px; color:#f59e0b; font-weight:700;">Đang chờ xử lý: ${pendingPO} phiếu</div>
                    </div>
                    <div style="background:#fff; border:1px solid #e2e8f0; border-radius:16px; padding:24px; box-shadow:0 4px 20px rgba(0,0,0,0.02); display:flex; flex-direction:column; gap:10px;">
                        <div style="font-size:13px; font-weight:700; color:#64748b; text-transform:uppercase; letter-spacing:1px;">Mức độ liên kết Đối tác</div>
                        <div style="display:flex; align-items:flex-end; gap:8px;">
                            <span style="font-size:28px; font-weight:900; color:#8b5cf6;">${Object.keys(supplierTotals).length}</span>
                            <span style="font-size:13px; font-weight:700; color:#64748b; margin-bottom:6px;">nhà cung cấp</span>
                        </div>
                    </div>
                </div>

                <div style="display:grid; grid-template-columns:1fr 1fr; gap:20px;">
                    <div class="card" style="background:#fff; border:1px solid #e2e8f0; border-radius:16px; overflow:hidden; box-shadow:0 10px 30px rgba(0,0,0,0.02); padding:24px;">
                        <h3 style="font-size:16px; font-weight:800; color:#1e293b; margin:0 0 20px 0;">Phân bổ Trạng thái Đơn hàng (PO)</h3>
                        <div style="display:flex; flex-direction:column; gap:16px;">
                            <div>
                                <div style="display:flex; justify-content:space-between; margin-bottom:6px; font-size:13px; font-weight:700;"><span color="#10b981">Đã nhận hàng</span> <span>${chartCounts.received} (${getPct(chartCounts.received)}%)</span></div>
                                <div style="width:100%; height:12px; background:#f1f5f9; border-radius:10px; overflow:hidden;">
                                    <div style="width:${getPct(chartCounts.received)}%; height:100%; background:#10b981;"></div>
                                </div>
                            </div>
                            <div>
                                <div style="display:flex; justify-content:space-between; margin-bottom:6px; font-size:13px; font-weight:700;"><span color="#3b82f6">Đã đặt hàng</span> <span>${chartCounts.ordered} (${getPct(chartCounts.ordered)}%)</span></div>
                                <div style="width:100%; height:12px; background:#f1f5f9; border-radius:10px; overflow:hidden;">
                                    <div style="width:${getPct(chartCounts.ordered)}%; height:100%; background:#3b82f6;"></div>
                                </div>
                            </div>
                            <div>
                                <div style="display:flex; justify-content:space-between; margin-bottom:6px; font-size:13px; font-weight:700;"><span color="#64748b">Bản Nháp</span> <span>${chartCounts.draft} (${getPct(chartCounts.draft)}%)</span></div>
                                <div style="width:100%; height:12px; background:#f1f5f9; border-radius:10px; overflow:hidden;">
                                    <div style="width:${getPct(chartCounts.draft)}%; height:100%; background:#94a3b8;"></div>
                                </div>
                            </div>
                            <div>
                                <div style="display:flex; justify-content:space-between; margin-bottom:6px; font-size:13px; font-weight:700;"><span color="#ef4444">Đã hủy</span> <span>${chartCounts.cancelled} (${getPct(chartCounts.cancelled)}%)</span></div>
                                <div style="width:100%; height:12px; background:#f1f5f9; border-radius:10px; overflow:hidden;">
                                    <div style="width:${getPct(chartCounts.cancelled)}%; height:100%; background:#ef4444;"></div>
                                </div>
                            </div>
                        </div>
                    </div>

                    <div class="card" style="background:#fff; border:1px solid #e2e8f0; border-radius:16px; overflow:hidden; box-shadow:0 10px 30px rgba(0,0,0,0.02);">
                        <div style="padding:24px; border-bottom:1px solid #f1f5f9;">
                            <h3 style="font-size:16px; font-weight:800; color:#1e293b; margin:0;">Top 5 Nhà cung cấp lớn nhất</h3>
                        </div>
                        <table style="width:100%; border-collapse:collapse;">
                            <tbody>
                                ${topSuppliers.length === 0 ? '<tr><td style="padding:20px;text-align:center;color:#94a3b8;">Chưa có dữ liệu thanh toán.</td></tr>' :
                topSuppliers.map((s, idx) => `
                                    <tr style="border-bottom:1px solid #f1f5f9;">
                                        <td style="padding:16px 24px; width:40px; text-align:center; font-weight:900; color:${idx === 0 ? '#f59e0b' : (idx === 1 ? '#94a3b8' : (idx === 2 ? '#b45309' : '#cbd5e1'))};">#${idx + 1}</td>
                                        <td style="padding:16px 12px; font-weight:700; color:#334155; font-size:14px;">${s.name}</td>
                                        <td style="padding:16px 24px; text-align:right; font-weight:800; color:#10b981;">${formatter.format(s.amount)}</td>
                                    </tr>
                                  `).join('')}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        `;
        pageContent.innerHTML = html;
    }

    window.erpApp.simulatePrintPurchasingReport = function () {
        showToast('Đang kết xuất Báo cáo Hệ thống...');
        setTimeout(() => {
            showToast('✅ Đã tải xuống file Baocao_Muahang_VIETBACH.pdf !');
        }, 1200);
    }


    // ==========================================
    // MODULE: Định mức nguyên vật liệu (BOM)
    // ==========================================
    let bomSearchQuery = '';
    let bomActiveTab = 'all';
    let boms = [
        {
            id: 'BOM-A001',
            productName: 'Áo sơ mi nam công sở',
            version: '1.0',
            baseQty: 1,
            status: 'active',
            items: [
                { name: 'Vải Cotton', unit: 'Mét', qty: 1.5, scrapPercent: 5, estimatePrice: 120000 },
                { name: 'Nút áo', unit: 'Cái', qty: 7, scrapPercent: 0, estimatePrice: 1000 },
                { name: 'Chỉ may', unit: 'Cuộn', qty: 0.1, scrapPercent: 2, estimatePrice: 15000 }
            ]
        },
        {
            id: 'BOM-Q001',
            productName: 'Quần tây Âu premium',
            version: '1.2',
            baseQty: 1,
            status: 'draft',
            items: [
                { name: 'Vải Wool', unit: 'Mét', qty: 1.8, scrapPercent: 10, estimatePrice: 350000 },
                { name: 'Khóa kéo', unit: 'Cái', qty: 1, scrapPercent: 0, estimatePrice: 5000 },
                { name: 'Cúc quần', unit: 'Cái', qty: 2, scrapPercent: 0, estimatePrice: 2000 }
            ]
        }
    ];

    try {
        const savedBoms = JSON.parse(localStorage.getItem('erp_boms'));
        if (savedBoms && Array.isArray(savedBoms)) {
            boms = savedBoms;
        }
    } catch (e) { }

    function renderBOM() {
        breadcrumbCurrent.textContent = 'Định mức nguyên vật liệu (BOM)';
        pageBadge.textContent = 'Sản xuất';

        const filteredBoms = boms.filter(bom => {
            const matchesSearch = bom.id.toLowerCase().includes(bomSearchQuery.toLowerCase()) ||
                bom.productName.toLowerCase().includes(bomSearchQuery.toLowerCase());
            const matchesTab = bomActiveTab === 'all' || bom.status === bomActiveTab;
            return matchesSearch && matchesTab;
        });

        const html = `
            <div class="bom-module" style="animation: fadeIn 0.4s ease-out;">
                <div class="module-header" style="display:flex; justify-content:space-between; align-items:center; margin-bottom:24px;">
                    <div style="display:flex; align-items:center; gap:16px;">
                        <button class="back-btn" onclick="window.erpApp.navigateTo('san-xuat')" style="padding:10px 16px; border:1px solid #e2e8f0; background:#fff; border-radius:12px; display:flex; align-items:center; gap:8px; font-weight:700; color:#64748b; cursor:pointer; transition:all 0.2s;">
                            <span class="material-icons-outlined">arrow_back</span> Quay lại
                        </button>
                        <div class="search-box" style="position:relative; width:400px;">
                            <span class="material-icons-outlined" style="position:absolute; left:12px; top:50%; transform:translateY(-50%); color:#94a3b8;">search</span>
                            <input type="text" placeholder="Tìm tên sản phẩm hoặc mã BOM..." value="${bomSearchQuery}" 
                                oninput="window.erpApp.handleBomSearch(this.value)"
                                style="width:100%; padding:12px 12px 12px 42px; border:1px solid #e2e8f0; border-radius:14px; outline:none; font-size:14px; transition:all 0.2s; background:#fcfdfe;" onfocus="this.style.border='1px solid #8b5cf6'; this.style.boxShadow='0 0 0 4px rgba(139, 92, 246, 0.1)'" onblur="this.style.border='1px solid #e2e8f0'; this.style.boxShadow='none'">
                        </div>
                    </div>
                    <button onclick="window.erpApp.openBomModal()" style="padding:12px 24px; background:linear-gradient(135deg, #8b5cf6 0%, #7c3aed 100%); color:#fff; border:none; border-radius:14px; font-weight:700; display:flex; align-items:center; gap:10px; cursor:pointer; box-shadow:0 10px 15px -3px rgba(139, 92, 246, 0.3); transition:all 0.2s;" onmouseover="this.style.transform='translateY(-2px)'" onmouseout="this.style.transform='none'">
                        <span class="material-icons-outlined">add_circle</span> Thiết lập Định mức mới
                    </button>
                </div>

                <div class="tabs" style="display:flex; gap:12px; margin-bottom:24px; background:#f1f5f9; padding:6px; border-radius:14px; width:fit-content;">
                    ${['all', 'active', 'draft', 'obsolete'].map(tab => `
                        <button onclick="window.erpApp.setBomTab('${tab}')" style="padding:10px 20px; border:none; border-radius:10px; font-size:14px; font-weight:700; cursor:pointer; transition:all 0.3s; ${bomActiveTab === tab ? 'background:#fff; color:#8b5cf6; box-shadow:0 4px 6px -1px rgba(0,0,0,0.1);' : 'background:transparent; color:#64748b;'}">
                            ${tab === 'all' ? 'Tất cả' : (tab === 'active' ? 'Đang áp dụng' : (tab === 'draft' ? 'Bản thảo' : 'Ngưng sử dụng'))}
                        </button>
                    `).join('')}
                </div>

                <div class="bom-grid" style="display:grid; grid-template-columns: repeat(auto-fill, minmax(360px, 1fr)); gap:24px;">
                    ${filteredBoms.length === 0 ? `
                        <div style="grid-column: 1/-1; text-align:center; padding:80px; background:#fff; border-radius:24px; border:2px dashed #e2e8f0;">
                            <span class="material-icons-outlined" style="font-size:48px; color:#cbd5e1; margin-bottom:16px;">account_tree</span>
                            <div style="color:#64748b; font-weight:600;">Không tìm thấy định mức nào phù hợp</div>
                        </div>
                    ` : filteredBoms.map(bom => {
            const totalCost = bom.items.reduce((sum, item) => sum + (item.qty * item.estimatePrice * (1 + (item.scrapPercent || 0) / 100)), 0);
            return `
                        <div class="bom-card" style="background:#fff; border:1px solid #e2e8f0; border-radius:24px; padding:24px; box-shadow: 0 4px 6px -1px rgba(0, 0, 0, 0.05); transition:all 0.3s; cursor:pointer; position:relative; overflow:hidden;" onmouseover="this.style.transform='translateY(-5px)'; this.style.boxShadow='0 20px 25px -5px rgba(0, 0, 0, 0.1)'; this.style.borderColor='#ddd6fe'" onmouseout="this.style.transform='none'; this.style.boxShadow='0 4px 6px -1px rgba(0, 0, 0, 0.05)'; this.style.borderColor='#e2e8f0'">
                            <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:16px;">
                                <div>
                                    <div style="font-size:12px; font-weight:800; color:#8b5cf6; letter-spacing:0.5px; margin-bottom:4px;">${bom.id}</div>
                                    <h3 style="margin:0; font-size:18px; font-weight:800; color:#1e293b;">${bom.productName}</h3>
                                </div>
                                <span style="padding:6px 14px; border-radius:10px; font-size:11px; font-weight:800; text-transform:uppercase; background:${bom.status === 'active' ? '#dcfce7' : (bom.status === 'draft' ? '#fef3c7' : '#f1f5f9')}; color:${bom.status === 'active' ? '#16a34a' : (bom.status === 'draft' ? '#b45309' : '#64748b')}">
                                    ${bom.status === 'active' ? 'Sử dụng' : (bom.status === 'draft' ? 'Nháp' : 'Đã đóng')}
                                </span>
                            </div>

                            <div style="display:flex; gap:20px; margin-bottom:20px; padding:16px; background:#f8fafc; border-radius:16px;">
                                <div style="flex:1;">
                                    <div style="font-size:11px; color:#94a3b8; font-weight:700; margin-bottom:2px;">Phiên bản</div>
                                    <div style="font-weight:700; color:#475569; font-size:15px;">v${bom.version}</div>
                                </div>
                                <div style="flex:1; border-left:1px solid #e2e8f0; padding-left:20px;">
                                    <div style="font-size:11px; color:#94a3b8; font-weight:700; margin-bottom:2px;">Tổng nguyên liệu</div>
                                    <div style="font-weight:700; color:#475569; font-size:15px;">${bom.items.length} Hạng mục</div>
                                </div>
                            </div>

                            <div style="display:flex; justify-content:space-between; align-items:center;">
                                <div>
                                    <div style="font-size:11px; color:#94a3b8; font-weight:700; margin-bottom:2px;">Ước tính giá vốn</div>
                                    <div style="font-weight:900; color:#10b981; font-size:20px;">${new Intl.NumberFormat('vi-VN').format(totalCost)} đ</div>
                                </div>
                                <div style="display:flex; gap:8px;">
                                    <button onclick="event.stopPropagation(); window.erpApp.cloneBOM('${bom.id}')" style="width:38px; height:38px; border-radius:10px; border:1px solid #e2e8f0; background:#fff; color:#64748b; display:flex; align-items:center; justify-content:center; cursor:pointer;" title="Nhân bản">
                                        <span class="material-icons-outlined" style="font-size:18px;">content_copy</span>
                                    </button>
                                    <button onclick="window.erpApp.openBomModal('${bom.id}')" style="width:38px; height:38px; border-radius:10px; border:1px solid #e2e8f0; background:#fff; color:#8b5cf6; display:flex; align-items:center; justify-content:center; cursor:pointer;" title="Sửa chi tiết">
                                        <span class="material-icons-outlined" style="font-size:18px;">edit</span>
                                    </button>
                                </div>
                            </div>
                        </div>
                        `;
        }).join('')}
                </div>
            </div>
        `;
        pageContent.innerHTML = html;
    }

    window.erpApp.handleBomSearch = function (val) {
        bomSearchQuery = val;
        renderBOM();
    };

    window.erpApp.setBomTab = function (tab) {
        bomActiveTab = tab;
        renderBOM();
    };

    window.erpApp.cloneBOM = function (id) {
        const source = boms.find(b => b.id === id);
        if (!source) return;

        const clone = JSON.parse(JSON.stringify(source));
        clone.id = `BOM-CLONE-${Date.now().toString().slice(-4)}`;
        clone.productName = `${source.productName} (Bản sao)`;
        clone.status = 'draft';

        boms.unshift(clone);
        localStorage.setItem('erp_boms', JSON.stringify(boms));
        showToast('Đã nhân bản định mức thành công!');
        renderBOM();
    };

    window.erpApp.openBomModal = function (id = null) {
        const bom = id ? boms.find(b => b.id === id) : {
            id: `BOM-${Date.now().toString().slice(-4)}`,
            productName: '',
            version: '1.0',
            baseQty: 1,
            status: 'draft',
            items: []
        };

        const modalHtml = `
            <div id="bomModal" class="modal-overlay" style="display:flex; justify-content:flex-end; animation: fadeIn 0.3s ease-out;">
                <div class="modal-content slide-in" style="width:850px; height:100%; border-radius:0; padding:0; display:flex; flex-direction:column; background:#f8fafc;">
                    <div class="modal-header" style="padding:24px 32px; background:#fff; border-bottom:1px solid #e2e8f0; display:flex; justify-content:space-between; align-items:center;">
                        <div>
                            <div style="font-size:12px; font-weight:800; color:#8b5cf6; text-transform:uppercase; letter-spacing:1px;">Cấu hình Định mức</div>
                            <h2 style="margin:0; font-size:24px; font-weight:900; color:#1e293b;">${id ? 'Cập nhật BOM' : 'Tạo mới Định mức'}</h2>
                        </div>
                        <button onclick="window.erpApp.closeBomModal()" style="width:40px; height:40px; border-radius:50%; border:none; background:#f1f5f9; cursor:pointer; display:flex; align-items:center; justify-content:center; color:#64748b;">
                            <span class="material-icons-outlined">close</span>
                        </button>
                    </div>

                    <div class="modal-body" style="padding:32px; overflow-y:auto; flex:1;">
                        <div style="display:grid; grid-template-columns: 2fr 1fr; gap:24px; margin-bottom:32px;">
                            <div style="background:#fff; padding:24px; border-radius:20px; box-shadow:0 4px 6px -1px rgba(0,0,0,0.05);">
                                <div style="margin-bottom:20px;">
                                    <label style="display:block; font-size:13px; font-weight:800; color:#475569; margin-bottom:8px;">Tên Thành phẩm Sản xuất</label>
                                    <input type="text" id="bomProductName" value="${bom.productName}" placeholder="VD: Áo Thun VietBach..." style="width:100%; padding:14px; border:1px solid #e2e8f0; border-radius:12px; outline:none; font-weight:600; color:#1e293b; background:#fcfdfe;">
                                </div>
                                <div style="display:grid; grid-template-columns: 1fr 1fr 1fr; gap:16px;">
                                    <div>
                                        <label style="display:block; font-size:12px; font-weight:800; color:#64748b; margin-bottom:8px;">Mã Định mức</label>
                                        <input type="text" id="bomCode" value="${bom.id}" style="width:100%; padding:12px; border:1px solid #e2e8f0; border-radius:10px; font-weight:700; color:#8b5cf6; background:#f8fafc;" readonly>
                                    </div>
                                    <div>
                                        <label style="display:block; font-size:12px; font-weight:800; color:#64748b; margin-bottom:8px;">Phiên bản</label>
                                        <input type="text" id="bomVersion" value="${bom.version}" style="width:100%; padding:12px; border:1px solid #e2e8f0; border-radius:10px; font-weight:700; color:#475569;">
                                    </div>
                                    <div>
                                        <label style="display:block; font-size:12px; font-weight:800; color:#64748b; margin-bottom:8px;">Số lượng cơ sở</label>
                                        <input type="number" id="bomBaseQty" value="${bom.baseQty}" style="width:100%; padding:12px; border:1px solid #e2e8f0; border-radius:10px; font-weight:700; color:#475569;">
                                    </div>
                                </div>
                            </div>

                            <div style="background:#fff; padding:24px; border-radius:20px; box-shadow:0 4px 6px -1px rgba(0,0,0,0.05); display:flex; flex-direction:column; justify-content:center; align-items:center;">
                                <div style="font-size:13px; font-weight:800; color:#64748b; margin-bottom:8px;">TỔNG GIÁ VỐN DỰ TÍNH</div>
                                <div id="bomTotalCost" style="font-size:32px; font-weight:950; color:#10b981;">0 đ</div>
                                <div style="font-size:11px; color:#94a3b8; font-weight:700; margin-top:8px;">(Cho ${bom.baseQty} Đơn vị TP)</div>
                            </div>
                        </div>

                        <div style="background:#fff; padding:24px; border-radius:20px; box-shadow:0 4px 6px -1px rgba(0,0,0,0.05);">
                            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:20px;">
                                <h3 style="margin:0; font-size:16px; font-weight:800; color:#1e293b;">Bảng Thành phần & Liên kết Vật liệu</h3>
                                <button onclick="window.erpApp.addBomItemRow()" style="padding:10px 18px; background:#f5f3ff; color:#7c3aed; border:1px dashed #c084fc; border-radius:10px; font-weight:700; cursor:pointer; display:flex; align-items:center; gap:8px;">
                                    <span class="material-icons-outlined" style="font-size:18px;">playlist_add</span> Thêm nguyên liệu
                                </button>
                            </div>

                            <div style="overflow-x:auto;">
                                <table style="width:100%; border-collapse:collapse;">
                                    <thead>
                                        <tr style="border-bottom:2px solid #f1f5f9;">
                                            <th style="padding:12px 0; text-align:left; font-size:12px; font-weight:800; color:#94a3b8; text-transform:uppercase;">Nguyên vật liệu</th>
                                            <th style="padding:12px 10px; text-align:left; font-size:12px; font-weight:800; color:#94a3b8; text-transform:uppercase;">ĐVT</th>
                                            <th style="padding:12px 10px; text-align:right; font-size:12px; font-weight:800; color:#94a3b8; text-transform:uppercase;">Số lượng</th>
                                            <th style="padding:12px 10px; text-align:right; font-size:12px; font-weight:800; color:#94a3b8; text-transform:uppercase;">Hao hụt (%)</th>
                                            <th style="padding:12px 10px; text-align:right; font-size:12px; font-weight:800; color:#94a3b8; text-transform:uppercase;">Đơn giá dự kiến</th>
                                            <th style="padding:12px 0; text-align:center; font-size:12px; font-weight:800; color:#94a3b8;">#</th>
                                        </tr>
                                    </thead>
                                    <tbody id="bomItemsList">
                                        ${bom.items.map((item, index) => renderBomItemRow(item, index)).join('')}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>

                    <div class="modal-footer" style="padding:24px 32px; background:#fff; border-top:1px solid #e2e8f0; display:flex; justify-content:space-between;">
                        <div style="display:flex; align-items:center; gap:12px;">
                            <label style="font-size:14px; font-weight:700; color:#475569;">Trạng thái:</label>
                            <select id="bomStatus" style="padding:10px 16px; border:1px solid #e2e8f0; border-radius:10px; outline:none; font-weight:700; color:#8b5cf6; cursor:pointer;">
                                <option value="draft" ${bom.status === 'draft' ? 'selected' : ''}>Bản thảo</option>
                                <option value="active" ${bom.status === 'active' ? 'selected' : ''}>Đang áp dụng</option>
                                <option value="obsolete" ${bom.status === 'obsolete' ? 'selected' : ''}>Ngưng sử dụng</option>
                            </select>
                        </div>
                        <div style="display:flex; gap:16px;">
                            <button onclick="window.erpApp.closeBomModal()" style="padding:12px 24px; background:#fff; color:#64748b; border:1px solid #e2e8f0; border-radius:14px; font-weight:700; cursor:pointer;">Hủy bỏ</button>
                            <button onclick="window.erpApp.saveBOM()" style="padding:12px 32px; background:linear-gradient(135deg, #8b5cf6 0%, #7c3aed 100%); color:#fff; border:none; border-radius:14px; font-weight:800; cursor:pointer; box-shadow:0 10px 15px -3px rgba(139, 92, 246, 0.3);">Lưu cấu hình Định mức</button>
                        </div>
                    </div>
                </div>
            </div>
        `;

        document.body.insertAdjacentHTML('beforeend', modalHtml);
        window.erpApp.updateBomTotal();

        // Add auto-calculation listeners
        document.getElementById('bomModal').addEventListener('input', (e) => {
            if (e.target.tagName === 'INPUT') {
                window.erpApp.updateBomTotal();
            }
        });
    }

    function renderBomItemRow(item = { name: '', unit: 'Mét', qty: 0, scrapPercent: 0, estimatePrice: 0 }, index) {
        return `
            <tr class="bom-item-row" data-index="${index}" style="border-bottom:1px solid #f1f5f9; height:60px;">
                <td style="padding:8px 0;"><input type="text" class="item-name" value="${item.name}" placeholder="Tên vật liệu..." style="width:100%; border:none; background:transparent; font-weight:700; color:#1e293b; outline:none;" onfocus="this.closest('td').style.borderBottom='2px solid #8b5cf6'" onblur="this.closest('td').style.borderBottom='none'"></td>
                <td style="padding:8px 10px;"><input type="text" class="item-unit" value="${item.unit}" style="width:100%; border:none; background:transparent; color:#64748b; font-size:13px; outline:none;"></td>
                <td style="padding:8px 10px;"><input type="number" class="item-qty" value="${item.qty}" style="width:80px; padding:6px; border:1px solid #e2e8f0; border-radius:6px; text-align:right; font-weight:700; color:#475569;"></td>
                <td style="padding:8px 10px;"><input type="number" class="item-scrap" value="${item.scrapPercent}" style="width:60px; padding:6px; border:1px solid #e2e8f0; border-radius:6px; text-align:right; background:#fff7ed; color:#c2410c;"></td>
                <td style="padding:8px 10px;"><input type="text" class="item-price" value="${new Intl.NumberFormat('vi-VN').format(item.estimatePrice)}" oninput="window.erpApp.formatVNDInput(this); window.erpApp.updateBomTotal()" style="width:120px; padding:6px; border:1px solid #e2e8f0; border-radius:6px; text-align:right; font-weight:700; color:#10b981; outline:none;"></td>
                <td style="padding:8px 0; text-align:center;"><button onclick="this.closest('tr').remove(); window.erpApp.updateBomTotal();" style="border:none; background:transparent; color:#ef4444; cursor:pointer;"><span class="material-icons-outlined">remove_circle_outline</span></button></td>
            </tr>
        `;
    }

    window.erpApp.addBomItemRow = function () {
        const list = document.getElementById('bomItemsList');
        const rows = list.querySelectorAll('.bom-item-row');
        const newIndex = rows.length;
        list.insertAdjacentHTML('beforeend', renderBomItemRow(undefined, newIndex));
    };

    window.erpApp.updateBomTotal = function () {
        const rows = document.querySelectorAll('.bom-item-row');
        let total = 0;
        rows.forEach(row => {
            const qty = parseFloat(row.querySelector('.item-qty').value) || 0;
            const scrap = parseFloat(row.querySelector('.item-scrap').value) || 0;
            const price = window.erpApp.parseVND(row.querySelector('.item-price').value) || 0;
            total += qty * price * (1 + scrap / 100);
        });
        document.getElementById('bomTotalCost').textContent = new Intl.NumberFormat('vi-VN').format(total) + ' đ';
    };

    window.erpApp.saveBOM = function () {
        const id = document.getElementById('bomCode').value;
        const productName = document.getElementById('bomProductName').value;
        if (!productName) { showToast('Vui lòng nhập tên thành phẩm!', 'error'); return; }

        const items = [];
        document.querySelectorAll('.bom-item-row').forEach(row => {
            items.push({
                name: row.querySelector('.item-name').value,
                unit: row.querySelector('.item-unit').value,
                qty: parseFloat(row.querySelector('.item-qty').value) || 0,
                scrapPercent: parseFloat(row.querySelector('.item-scrap').value) || 0,
                estimatePrice: window.erpApp.parseVND(row.querySelector('.item-price').value) || 0
            });
        });

        const newBom = {
            id,
            productName,
            version: document.getElementById('bomVersion').value,
            baseQty: parseFloat(document.getElementById('bomBaseQty').value) || 1,
            status: document.getElementById('bomStatus').value,
            items
        };

        const idx = boms.findIndex(b => b.id === id);
        if (idx > -1) boms[idx] = newBom;
        else boms.unshift(newBom);

        localStorage.setItem('erp_boms', JSON.stringify(boms));
        showToast('Đã lưu cấu hình định mức nguyên liệu thành công!');
        window.erpApp.closeBomModal();
        renderBOM();
    };

    window.erpApp.closeBomModal = function () {
        const m = document.getElementById('bomModal');
        if (m) m.remove();
    };

    window.erpApp.renderBOM = renderBOM;


