        {
            id: 'WC-001',
            name: 'Xưởng Cắt Laser 01',
            type: 'Máy móc',
            capacity: 500,
            unit: 'Sản phẩm/Ngày',
            efficiency: 85,
            oee: 78,
            status: 'running' // running, maintenance, idle
        },
        {
            id: 'WC-002',
            name: 'Tổ May Công Nghiệp A2',
            type: 'Con người',
            capacity: 200,
            unit: 'Sản phẩm/Ngày',
            efficiency: 92,
            oee: 88,
            status: 'running'
        },
        {
            id: 'WC-003',
            name: 'Máy In 3D Markforged',
            type: 'Máy móc',
            capacity: 50,
            unit: 'Sản phẩm/Ngày',
            efficiency: 95,
            oee: 65,
            status: 'maintenance'
        }
