    function renderRoutingStepRow(step = { op: '', workCenter: '', duration: 10, laborCost: 0, desc: '' }, index) {
        const wcOptions = workCenters.map(wc => `<option value="${wc.name}" ${step.workCenter === wc.name ? 'selected' : ''}>${wc.name}</option>`).join('');
        return `
            <div class="rt-step-row" style="background:#f8fafc; border:1px solid #e2e8f0; border-radius:16px; padding:16px; display:flex; flex-direction:column; gap:12px; position:relative;">
                <div style="display:grid; grid-template-columns: 2fr 1fr 80px 120px 40px; gap:12px; align-items:flex-end;">
                    <div>
                        <label style="display:block; font-size:10px; font-weight:800; color:#94a3b8; margin-bottom:4px; text-transform:uppercase;">Công đoạn</label>
                        <input type="text" class="step-op" value="${step.op}" placeholder="VD: Cắt phôi, Ráp thân..." style="width:100%; padding:10px; border:1px solid #e2e8f0; border-radius:10px; font-weight:700;">
                    </div>
                    <div>
                        <label style="display:block; font-size:10px; font-weight:800; color:#94a3b8; margin-bottom:4px; text-transform:uppercase;">Work Center</label>
                        <select class="step-wc" style="width:100%; padding:10px; border:1px solid #e2e8f0; border-radius:10px; font-weight:600;">
                            ${wcOptions || '<option value="">(Chọn Work Center)</option>'}
                        </select>
                    </div>
                    <div>
                        <label style="display:block; font-size:10px; font-weight:800; color:#94a3b8; margin-bottom:4px; text-transform:uppercase;">Thời gian (phút)</label>
                        <input type="number" class="step-dur" value="${step.duration}" oninput="window.erpApp.updateRtTotals()" style="width:100%; padding:10px; border:1px solid #e2e8f0; border-radius:10px; font-weight:700; text-align:center;">
                    </div>
                    <div>
                        <label style="display:block; font-size:10px; font-weight:800; color:#94a3b8; margin-bottom:4px; text-transform:uppercase;">Nhân công (VNĐ)</label>
                        <input type="number" class="step-labor" value="${step.laborCost}" oninput="window.erpApp.updateRtTotals()" style="width:100%; padding:10px; border:1px solid #e2e8f0; border-radius:10px; font-weight:700; text-align:right; color:#059669;">
                    </div>
                    <button onclick="this.closest('.rt-step-row').remove(); window.erpApp.updateRtTotals();" style="border:none; background:#fee2e2; color:#ef4444; width:36px; height:36px; border-radius:10px; cursor:pointer; display:flex; align-items:center; justify-content:center;">
                        <span class="material-icons-outlined" style="font-size:18px;">delete</span>
                    </button>
                </div>
                <div>
                    <input type="text" class="step-desc" value="${step.desc || ''}" placeholder="Mô tả / Lưu ý thực hiện..." style="width:100%; padding:10px; border:1px solid transparent; border-bottom:1px dashed #cbd5e1; background:transparent; font-size:12px; color:#64748b; outline:none;" onfocus="this.style.borderBottom='1px solid #3b82f6'">
                </div>
            </div>
        `;
    }

    window.erpApp.addRoutingStep = function () {
        const list = document.getElementById('routingStepsList');
        const nextIdx = list.children.length;
        list.insertAdjacentHTML('beforeend', renderRoutingStepRow(undefined, nextIdx));
    };

    window.erpApp.updateRtTotals = function () {
        const rows = document.querySelectorAll('.rt-step-row');
        let totalTime = 0;
        let totalLabor = 0;
        rows.forEach(row => {
            totalTime += parseInt(row.querySelector('.step-dur').value) || 0;
            totalLabor += parseInt(row.querySelector('.step-labor').value) || 0;
        });
        document.getElementById('totalRtTime').textContent = `${totalTime} phút`;
        document.getElementById('totalRtLabor').textContent = `${new Intl.NumberFormat('vi-VN').format(totalLabor)} đ`;
    };

    window.erpApp.saveRouting = function () {
        const id = document.getElementById('rtId').value;
        const name = document.getElementById('rtName').value;
        if (!name) { showToast('Vui lòng nhập tên quy trình!', 'error'); return; }

        const steps = [];
        document.querySelectorAll('.rt-step-row').forEach(row => {
            steps.push({
                op: row.querySelector('.step-op').value,
                workCenter: row.querySelector('.step-wc').value,
                duration: parseInt(row.querySelector('.step-dur').value) || 0,
                laborCost: parseInt(row.querySelector('.step-labor').value) || 0,
                desc: row.querySelector('.step-desc').value
            });
        });

        const data = {
            id,
            name,
            version: document.getElementById('rtVer').value,
            status: document.getElementById('rtStatus').value,
            steps
        };

        const idx = routings.findIndex(r => r.id === id);
        if (idx > -1) routings[idx] = data;
        else routings.unshift(data);

        localStorage.setItem('erp_routings', JSON.stringify(routings));
        showToast('Đã lưu dữ liệu Quy trình sản xuất!');
        window.erpApp.closeRtModal();
        renderRouting();
    };

    window.erpApp.closeRtModal = function () {
        const m = document.getElementById('rtModal');
        if (m) m.remove();
    };


    window.erpApp.renderRouting = renderRouting;

