                                <textarea oninput="window.erpApp.updateStrategyData(${i}, 'goals', this.value)" 
                                    style="width:100%; border:none; background:transparent; color:#64748b; font-size:15px; line-height:1.7; outline:none; padding:4px 8px; border-radius:8px; resize:none; font-family:inherit; min-height:80px;" 
                                    placeholder="Chi tiết mục tiêu và kế hoạch..." onfocus="this.style.background='#f8fafc'; this.style.boxShadow='0 0 0 2px #eff6ff';">${s.goals}</textarea>
