    function renderTheoDoiDanhGia() {
        breadcrumbCurrent.textContent = 'Theo dõi & Đánh giá';
        let html = `
            <div class="exec-module-container" style="max-width:1200px; padding:20px; animation:fadeIn 0.5s ease-out;">
                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:40px;">
                    <button class="back-btn" onclick="window.erpApp.renderDieuHanh()" style="padding:12px 24px; border:1px solid #e2e8f0; background:#fff; border-radius:14px; display:flex; align-items:center; gap:10px; font-weight:700; color:#475569; cursor:pointer;" onmouseover="this.style.background='#f8fafc';">
                        <span class="material-icons-outlined">arrow_back</span> Quay lại bộ chỉ số
                    </button>
                    <h2 style="font-size:24px; font-weight:900; color:#1e293b; margin:0;">THEO DÕI HIỆU SUẤT</h2>
                </div>
                <div style="display:grid; grid-template-columns:repeat(auto-fill, minmax(380px, 1fr)); gap:32px;">
                    ${execStrategyData.kpis.map(k => {
            const progress = Math.min(100, (k.actual / k.target * 100).toFixed(1));
            const color = progress >= 100 ? '#10b981' : progress >= 80 ? '#3b82f6' : '#f59e0b';
            return `
                        <div class="premium-card" style="background:#fff; border:1px solid #e2e8f0; border-radius:32px; padding:32px; box-shadow:0 10px 30px rgba(0,0,0,0.02); transition:all 0.3s;" onmouseover="this.style.transform='translateY(-5px)';" onmouseout="this.style.transform='translateY(0)';">
                            <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:16px;">
                                <h3 style="margin:0; font-size:18px; font-weight:900; color:#1e293b;">${k.name}</h3>
                                <span style="font-weight:900; color:${color}; font-size:20px;">${progress}%</span>
                            </div>
                            <div style="width:100%; height:16px; background:#f1f5f9; border-radius:8px; overflow:hidden; margin-bottom:24px;">
                                <div style="width:${progress}%; height:100%; background:${color}; border-radius:8px;"></div>
                            </div>
                            <div style="display:flex; justify-content:space-between;">
                                <div><span style="font-size:10px; font-weight:800; color:#94a3b8;">THỰC TẾ:</span> <div style="font-weight:900;">${k.actual} ${k.unit}</div></div>
                                <div style="text-align:right;"><span style="font-size:10px; font-weight:800; color:#94a3b8;">MỤC TIÊU:</span> <div style="font-weight:900;">${k.target} ${k.unit}</div></div>
                            </div>
                        </div>
                    `;
        }).join('')}
                </div>
            </div>
        `;
        pageContent.innerHTML = html;
        pageContent.scrollTop = 0;
    }

