        const inactive = data.filter(e => e.status === 'inactive').length;

        const activePct = total > 0 ? Math.round((active / total) * 100) : 0;
        const probationPct = total > 0 ? Math.round((probation / total) * 100) : 0;
        const inactivePct = total > 0 ? Math.round((inactive / total) * 100) : 0;

        // Dept Distribution
        const deptMap = data.reduce((acc, curr) => {
            acc[curr.department] = (acc[curr.department] || 0) + 1;
            return acc;
        }, {});
        const sortedDepts = Object.entries(deptMap).sort((a, b) => b[1] - a[1]);

        // Gender Dist
        const male = data.filter(e => e.gender === 'Nam').length;
        const female = data.filter(e => e.gender === 'Nữ').length;
        const malePct = total > 0 ? Math.round((male / total) * 100) : 50;
        const femalePct = 100 - malePct;

        // Dynamic Gradient for Dept Donut
        const colors = ['#3B82F6', '#10B981', '#F59E0B', '#6366F1', '#EC4899', '#8B5CF6', '#14B8A6', '#F43F5E'];
