    // Google Drive Integration
    const GOOGLE_CLIENT_ID = '814327586951-5j1pbfnui0d5fapsdsod2a0r4q04edbi.apps.googleusercontent.com';
    const GOOGLE_API_KEY = 'AIzaSyAv1FZeYwrWc5MAHtcu_uD382zycRyaGZ0';
    const DISCOVERY_DOC = 'https://www.googleapis.com/discovery/v1/apis/drive/v3/rest';
    const SCOPES = 'https://www.googleapis.com/auth/drive.file';
    let tokenClient;
    let gapiInited = false;
    let gisInited = false;

    window.erpApp.initDrive = function () {
        if (gapiInited && gisInited) return;
        if (typeof gapi === 'undefined' || typeof google === 'undefined') return;

        gapi.load('client', async () => {
            await gapi.client.init({ apiKey: GOOGLE_API_KEY, discoveryDocs: [DISCOVERY_DOC] });
            gapiInited = true;
        });
        tokenClient = google.accounts.oauth2.initTokenClient({
            client_id: GOOGLE_CLIENT_ID, scope: SCOPES, callback: '',
        });
        gisInited = true;
    };

    async function uploadToDrive(fileObj) {
        return new Promise((resolve, reject) => {
            if (!tokenClient) { reject('Drive not initialized'); return; }
            tokenClient.callback = async (resp) => {
                if (resp.error !== undefined) { reject(resp); return; }
                try {
                    const metadata = { name: fileObj.name, parents: [DRIVE_FOLDER_ID] };
                    const trimmedData = fileObj.dataUrl.split(',')[1];
                    const boundary = '-------314159265358979323846';
                    const delimiter = "\r\n--" + boundary + "\r\n";
                    const close_delim = "\r\n--" + boundary + "--";
                    const contentType = fileObj.dataUrl.match(/data:([^;]+);/)[1] || 'application/octet-stream';

                    const multipartRequestBody =
                        delimiter + 'Content-Type: application/json\r\n\r\n' + JSON.stringify(metadata) +
                        delimiter + 'Content-Type: ' + contentType + '\r\n' + 'Content-Transfer-Encoding: base64\r\n\r\n' +
                        trimmedData + close_delim;

                    const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart&fields=id,name,webViewLink', {
                        method: 'POST',
                        headers: { 'Authorization': 'Bearer ' + resp.access_token, 'Content-Type': 'multipart/related; boundary=' + boundary },
                        body: multipartRequestBody
                    });
                    const result = await response.json();
                    resolve({ id: result.id, name: result.name, driveUrl: result.webViewLink, type: fileObj.type });
                } catch (err) { reject(err); }
            };
            if (gapi.client.getToken() === null) { tokenClient.requestAccessToken({ prompt: 'consent' }); }
            else { tokenClient.requestAccessToken({ prompt: '' }); }
        });
    }

    function deletePhieuKho(id) {
        pkList = pkList.filter(p => p.id !== id);
        const m = document.getElementById('pkDeleteModal');
        if (m) { m.classList.add('closing'); setTimeout(() => m.remove(), 200); }
        showToast('Đã xóa ' + id); renderPhieuKho();
    }

    function deletePkItemRow(pkId, itemIdx) {
        const pk = pkList.find(p => p.id === pkId);
        if (!pk) return;

        if (pk.items.length <= 1) {
            confirmDeletePk(pkId);
        } else {
            const itemName = pk.items[itemIdx].name;
            pk.items.splice(itemIdx, 1);
            showToast(`Đã xóa mặt hàng "${itemName}" khỏi phiếu ${pkId}`);
            renderPhieuKho();
        }
    }
