    window.erpApp.saveDmhh = function () {
        const isEdit = !!document.getElementById('dmhhOldId').value;
        const id = document.getElementById('dmhhId').value.trim();
        const name = document.getElementById('dmhhName').value.trim();
        const parent = document.getElementById('dmhhParent').value;
        const order = 0;
        const desc = document.getElementById('dmhhDesc').value.trim();
        const status = document.getElementById('dmhhStatus').value;

        if (!id || !name) {
            showToast('Mã và tên danh mục không được để trống.', 'error');
            return;
        }

        const dateStr = new Date().toLocaleDateString('vi-VN');

        if (isEdit) {
            let item = danhMucHangHoaData.find(d => d.id === id);
            if (item) {
                item.name = name;
                item.parent = parent;
                item.order = order;
                item.desc = desc;
                item.status = status;
                item.updated = dateStr;
            }
        } else {
            if (danhMucHangHoaData.find(d => d.id === id)) {
                showToast('Mã danh mục đã tồn tại.', 'error');
                return;
            }
            danhMucHangHoaData.push({ id, name, parent, desc, order, status, updated: dateStr });
        }

        window.erpApp.closeDmhhModal();
        window.erpApp.renderDanhMucHangHoa();
        showToast(isEdit ? 'Cập nhật thành công' : 'Thêm mới thành công');
    };

    window.erpApp.deleteDmhh = function (id) {
        if (confirm(`Bạn có chắc muốn xóa danh mục ${id}?`)) {
            // Validate if it has children
            if (danhMucHangHoaData.some(d => d.parent === id)) {
                showToast('Không thể xóa danh mục gốc chứa danh mục con. Hãy xóa các danh mục con trước.', 'error');
                return;
            }

            danhMucHangHoaData = danhMucHangHoaData.filter(d => d.id !== id);
            window.erpApp.renderDanhMucHangHoa();
            showToast('Đã xóa danh mục');
        }
    };

