        openPkCameraModal: () => {
            const modal = document.createElement('div');
            modal.className = 'modal-overlay'; modal.id = 'pkCameraModal';
            modal.innerHTML = `<div class="modal-content" style="max-width:500px">
                <div class="modal-header"><h3><span class="material-icons-outlined">photo_camera</span> Chụp ảnh chứng từ</h3>
                    <button class="modal-close" onclick="document.getElementById('pkCameraModal').remove()"><span class="material-icons-outlined">close</span></button>
                </div>
                <div class="modal-body" style="padding:0; background:#000; position:relative; overflow:hidden; aspect-ratio:4/3">
                    <video id="pkVideo" autoplay playsinline style="width:100%; height:100%; object-fit:cover"></video>
                    <canvas id="pkCanvas" style="display:none"></canvas>
                </div>
                <div class="modal-footer" style="justify-content:center; padding:20px">
                    <button class="btn-save" style="border-radius:50%; width:60px; height:60px; padding:0" onclick="window.erpApp.capturePkPhoto()">
                        <span class="material-icons-outlined" style="font-size:32px">camera</span>
                    </button>
                </div>
            </div>`;
            document.body.appendChild(modal);
            const video = document.getElementById('pkVideo');
            navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
                .then(stream => { video.srcObject = stream; window.pkCameraStream = stream; })
                .catch(err => { console.error('Camera error:', err); showToast('Không thể truy cập camera!'); document.getElementById('pkCameraModal').remove(); });
        },
        capturePkPhoto: () => {
            const video = document.getElementById('pkVideo');
            const canvas = document.getElementById('pkCanvas');
            canvas.width = video.videoWidth; canvas.height = video.videoHeight;
            canvas.getContext('2d').drawImage(video, 0, 0);
            const dataUrl = canvas.toDataURL('image/jpeg');
            const fileName = `pk_photo_${Date.now()}.jpg`;
            tempPkFiles.push({ name: fileName, size: '—', type: 'jpg', dataUrl: dataUrl, status: 'pending' });

            if (window.pkCameraStream) window.pkCameraStream.getTracks().forEach(t => t.stop());
            document.getElementById('pkCameraModal').remove();
            const el = document.getElementById('pkFileList');
            if (el && window.erpApp.renderHsFileList) el.innerHTML = window.erpApp.renderHsFileList(tempPkFiles, true, 'pk-edit');
        },
