    // Internal Sync Helpers
    window.erpApp._getData = (name) => {
        switch(name) {
            case 'employees': return employees;
            case 'hoSoDocuments': return hoSoDocuments;
            case 'hoSoProjects': return hoSoProjects;
            case 'congVanList': return congVanList;
            case 'contracts': return contracts;
            case 'inventory_items': return danhSachHangHoaData;
            case 'warehousing_slips': return pkList;
            case 'goods_receipts': return goodsReceipts;
            case 'projects': return danhSachDuAnData;
            case 'material_proposals': return (window.erpApp.mp_getData ? window.erpApp.mp_getData() : []);
            default: return [];
        }
    };

    window.erpApp._setData = (name, data) => {
        switch(name) {
            case 'employees': employees = data; break;
            case 'hoSoDocuments': hoSoDocuments = data; break;
            case 'hoSoProjects': hoSoProjects = data; break;
            case 'congVanList': congVanList = data; break;
            case 'contracts': contracts = data; break;
            case 'inventory_items': danhSachHangHoaData = data; break;
            case 'warehousing_slips': pkList = data; break;
            case 'goods_receipts': goodsReceipts = data; break;
            case 'projects': danhSachDuAnData = data; break;
            case 'material_proposals': if (window.erpApp.mp_setData) window.erpApp.mp_setData(data); break;
        }
        // Re-render current page if active
        const currentPage = window.erpApp.getCurrentPage();
        if (currentPage) window.erpApp.renderPage(currentPage);
    };

